#!/bin/bash
# Quick dual-system resource status
echo "=== LOCAL (terex) ===" && hostname && uptime && echo "CPU: $(nproc) cores" && free -h | grep -E "^Mem|^Swap" && echo "Disk:" && df -h --total 2>/dev/null | grep -E "^(/dev|Filesystem)" && echo "Docker: $(docker info 2>/dev/null | grep 'Running:' | awk '{print $2}' || echo 'Not running')" && echo "" && echo "=== REMOTE (srv686563) ===" && ssh -o ConnectTimeout=5 -o StrictHostKeyChecking=no root@147.79.71.192 'echo "Hostname: $(hostname)" && uptime && echo "CPU: $(nproc) cores" && free -h | grep -E "^Mem|^Swap" && echo "Disk:" && df -h --total 2>/dev/null | grep -E "^(/dev|Filesystem)" && echo "Docker: $(docker info 2>/dev/null | grep '\''Running:'\'' | awk '\''{print $2}'\'' || echo '\''Not running'\'')" && echo "GPU: $(nvidia-smi --query-gpu=name --format=csv,noheader 2>/dev/null || echo '\''None'\'')" && echo "" && echo "=== TOP 5 PROCESSES (Remote) ===" && ps aux --sort=-%mem | head -6'